package org.apache.commons.csv;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.QuoteMode;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Constructor;

import static org.junit.jupiter.api.Assertions.*;

class CSVFormatTest {

    @Test
    void testIsQuoteCharacterSet_whenQuoteCharacterIsNonNull() throws Exception {
        Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(
                char.class,
                Character.class,
                QuoteMode.class,
                Character.class,
                Character.class,
                boolean.class,
                boolean.class,
                String.class,
                String.class,
                Object[].class,
                String[].class,
                boolean.class,
                boolean.class,
                boolean.class);
        constructor.setAccessible(true);
        CSVFormat csvFormat = constructor.newInstance(
                ',',        // delimiter
                '\"',       // quoteCharacter non-null
                null,       // quoteMode
                null,       // commentMarker
                null,       // escapeCharacter
                false,      // ignoreSurroundingSpaces
                false,      // ignoreEmptyLines
                "\n",       // recordSeparator
                null,       // nullString
                null,       // headerComments
                null,       // header
                false,      // skipHeaderRecord
                false,      // allowMissingColumnNames
                false       // ignoreHeaderCase
        );

        assertTrue(csvFormat.isQuoteCharacterSet());
    }

    @Test
    void testIsQuoteCharacterSet_whenQuoteCharacterIsNull() throws Exception {
        Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(
                char.class,
                Character.class,
                QuoteMode.class,
                Character.class,
                Character.class,
                boolean.class,
                boolean.class,
                String.class,
                String.class,
                Object[].class,
                String[].class,
                boolean.class,
                boolean.class,
                boolean.class);
        constructor.setAccessible(true);
        CSVFormat csvFormat = constructor.newInstance(
                ',',        // delimiter
                null,       // quoteCharacter null
                null,       // quoteMode
                null,       // commentMarker
                null,       // escapeCharacter
                false,      // ignoreSurroundingSpaces
                false,      // ignoreEmptyLines
                "\n",       // recordSeparator
                null,       // nullString
                null,       // headerComments
                null,       // header
                false,      // skipHeaderRecord
                false,      // allowMissingColumnNames
                false       // ignoreHeaderCase
        );

        assertFalse(csvFormat.isQuoteCharacterSet());
    }
}
